import React, { useState } from 'react';
import { loginAdmin } from '../../services/api';
import { FaUser, FaLock, FaRobot, FaArrowRight, FaShieldAlt, FaBrain, FaCheckCircle } from 'react-icons/fa';

const LoginPage = ({ onLogin }) => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    try {
      const response = await loginAdmin(username, password);
      if (response.data.access_token) {
        onLogin(response.data.access_token);
      }
    } catch (err) {
      setError('Invalid credentials! Use varshini / varshu');
    }
    setLoading(false);
  };

  return (
    <div style={{
      minHeight: '100vh',
      background: 'linear-gradient(135deg, #0f172a 0%, #4c1d95 50%, #0f172a 100%)',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      padding: '16px',
      position: 'relative',
      overflow: 'hidden'
    }}>
      {/* Animated Background Elements */}
      <div style={{
        position: 'absolute',
        inset: 0,
        overflow: 'hidden'
      }}>
        <div style={{
          position: 'absolute',
          top: '-160px',
          right: '-160px',
          width: '320px',
          height: '320px',
          background: '#a855f7',
          borderRadius: '50%',
          filter: 'blur(80px)',
          opacity: 0.3,
          animation: 'blob 7s infinite'
        }}></div>
        <div style={{
          position: 'absolute',
          bottom: '-160px',
          left: '-160px',
          width: '320px',
          height: '320px',
          background: '#3b82f6',
          borderRadius: '50%',
          filter: 'blur(80px)',
          opacity: 0.3,
          animation: 'blob 7s infinite 2s'
        }}></div>
        <div style={{
          position: 'absolute',
          top: '50%',
          left: '50%',
          transform: 'translate(-50%, -50%)',
          width: '320px',
          height: '320px',
          background: '#ec4899',
          borderRadius: '50%',
          filter: 'blur(80px)',
          opacity: 0.3,
          animation: 'blob 7s infinite 4s'
        }}></div>
      </div>

      {/* Main Container */}
      <div style={{
        position: 'relative',
        zIndex: 10,
        width: '100%',
        maxWidth: '1024px'
      }}>
        <div style={{
          display: 'grid',
          gridTemplateColumns: '1fr 1fr',
          gap: '32px'
        }}>
          {/* Left Side - Brand Section */}
          <div style={{
            display: 'flex',
            flexDirection: 'column',
            justifyContent: 'center',
            color: 'white',
            gap: '24px'
          }}>
            <div style={{
              display: 'inline-flex',
              alignItems: 'center',
              gap: '12px',
              background: 'rgba(255,255,255,0.1)',
              backdropFilter: 'blur(8px)',
              borderRadius: '16px',
              padding: '16px',
              width: 'fit-content',
              border: '1px solid rgba(255,255,255,0.2)'
            }}>
              <div style={{
                background: 'linear-gradient(135deg, #a855f7, #3b82f6)',
                padding: '12px',
                borderRadius: '12px'
              }}>
                <FaBrain size={32} />
              </div>
              <div style={{
                background: 'linear-gradient(135deg, #a855f7, #3b82f6)',
                padding: '12px',
                borderRadius: '12px'
              }}>
                <FaRobot size={32} />
              </div>
            </div>

            <h1 style={{
              fontSize: '48px',
              fontWeight: 'bold',
              lineHeight: 1.2,
              margin: 0
            }}>
              AI Resume
              <br />
              <span style={{
                background: 'linear-gradient(135deg, #c084fc, #f472b6)',
                WebkitBackgroundClip: 'text',
                WebkitTextFillColor: 'transparent',
                backgroundClip: 'text'
              }}>
                Screening System
              </span>
            </h1>

            <p style={{
              fontSize: '18px',
              color: '#d8b4fe',
              lineHeight: 1.6,
              margin: 0
            }}>
              Intelligent parsing, automated screening, and smart candidate matching powered by advanced AI technology.
            </p>

            <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
              <div style={{ display: 'flex', alignItems: 'center', gap: '12px', color: '#d8b4fe' }}>
                <FaCheckCircle color="#4ade80" />
                <span>AI-powered resume parsing</span>
              </div>
              <div style={{ display: 'flex', alignItems: 'center', gap: '12px', color: '#d8b4fe' }}>
                <FaCheckCircle color="#4ade80" />
                <span>Smart candidate ranking</span>
              </div>
              <div style={{ display: 'flex', alignItems: 'center', gap: '12px', color: '#d8b4fe' }}>
                <FaCheckCircle color="#4ade80" />
                <span>Real-time analytics dashboard</span>
              </div>
            </div>

            {/* Stats */}
            <div style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(3, 1fr)',
              gap: '16px',
              paddingTop: '24px'
            }}>
              <div style={{
                background: 'rgba(255,255,255,0.05)',
                backdropFilter: 'blur(8px)',
                borderRadius: '12px',
                padding: '12px',
                textAlign: 'center',
                border: '1px solid rgba(255,255,255,0.1)'
              }}>
                <div style={{ fontSize: '24px', fontWeight: 'bold' }}>500+</div>
                <div style={{ fontSize: '12px', color: '#d8b4fe' }}>Resumes Processed</div>
              </div>
              <div style={{
                background: 'rgba(255,255,255,0.05)',
                backdropFilter: 'blur(8px)',
                borderRadius: '12px',
                padding: '12px',
                textAlign: 'center',
                border: '1px solid rgba(255,255,255,0.1)'
              }}>
                <div style={{ fontSize: '24px', fontWeight: 'bold' }}>98%</div>
                <div style={{ fontSize: '12px', color: '#d8b4fe' }}>Accuracy Rate</div>
              </div>
              <div style={{
                background: 'rgba(255,255,255,0.05)',
                backdropFilter: 'blur(8px)',
                borderRadius: '12px',
                padding: '12px',
                textAlign: 'center',
                border: '1px solid rgba(255,255,255,0.1)'
              }}>
                <div style={{ fontSize: '24px', fontWeight: 'bold' }}>24/7</div>
                <div style={{ fontSize: '12px', color: '#d8b4fe' }}>AI Processing</div>
              </div>
            </div>
          </div>

          {/* Right Side - Login Form */}
          <div>
            <div style={{
              background: 'rgba(255,255,255,0.1)',
              backdropFilter: 'blur(16px)',
              borderRadius: '16px',
              boxShadow: '0 25px 50px -12px rgba(0,0,0,0.25)',
              padding: '32px',
              border: '1px solid rgba(255,255,255,0.2)'
            }}>
              {/* Mobile Brand */}
              <div style={{
                display: 'none',
                textAlign: 'center',
                marginBottom: '24px'
              }}>
                <div style={{
                  display: 'inline-flex',
                  alignItems: 'center',
                  gap: '8px',
                  background: 'linear-gradient(135deg, #a855f7, #3b82f6)',
                  padding: '8px',
                  borderRadius: '12px',
                  marginBottom: '12px'
                }}>
                  <FaBrain size={24} color="white" />
                  <FaRobot size={24} color="white" />
                </div>
                <h2 style={{ fontSize: '24px', fontWeight: 'bold', color: 'white', margin: 0 }}>AI Resume Screening</h2>
                <p style={{ color: '#d8b4fe', fontSize: '14px', margin: '8px 0 0 0' }}>Admin Portal</p>
              </div>

              <div style={{
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'space-between',
                marginBottom: '24px'
              }}>
                <h3 style={{ fontSize: '24px', fontWeight: 'semibold', color: 'white', margin: 0 }}>Admin Login</h3>
                <FaShieldAlt size={24} color="#d8b4fe" />
              </div>

              {/* Error Alert */}
              {error && (
                <div style={{
                  marginBottom: '16px',
                  background: 'rgba(239, 68, 68, 0.2)',
                  border: '1px solid rgba(239, 68, 68, 0.5)',
                  borderRadius: '8px',
                  padding: '12px'
                }}>
                  <p style={{ color: '#fecaca', fontSize: '14px', textAlign: 'center', margin: 0 }}>{error}</p>
                </div>
              )}

              <form onSubmit={handleSubmit} style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}>
                {/* Username Field */}
                <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
                  <label style={{ fontSize: '14px', fontWeight: '500', color: '#d8b4fe' }}>
                    Username
                  </label>
                  <div style={{ position: 'relative' }}>
                    <div style={{
                      position: 'absolute',
                      left: '12px',
                      top: '50%',
                      transform: 'translateY(-50%)',
                      pointerEvents: 'none'
                    }}>
                      <FaUser color="#c084fc" size={18} />
                    </div>
                    <input
                      type="text"
                      placeholder="Enter your username"
                      value={username}
                      onChange={(e) => setUsername(e.target.value)}
                      style={{
                        width: '100%',
                        padding: '12px 12px 12px 40px',
                        background: 'rgba(255,255,255,0.1)',
                        border: '1px solid rgba(168, 85, 247, 0.3)',
                        borderRadius: '12px',
                        color: 'white',
                        fontSize: '16px',
                        outline: 'none',
                        transition: 'all 0.3s'
                      }}
                      required
                      disabled={loading}
                      onFocus={(e) => e.target.style.borderColor = '#a855f7'}
                      onBlur={(e) => e.target.style.borderColor = 'rgba(168, 85, 247, 0.3)'}
                    />
                  </div>
                </div>

                {/* Password Field */}
                <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
                  <label style={{ fontSize: '14px', fontWeight: '500', color: '#d8b4fe' }}>
                    Password
                  </label>
                  <div style={{ position: 'relative' }}>
                    <div style={{
                      position: 'absolute',
                      left: '12px',
                      top: '50%',
                      transform: 'translateY(-50%)',
                      pointerEvents: 'none'
                    }}>
                      <FaLock color="#c084fc" size={18} />
                    </div>
                    <input
                      type="password"
                      placeholder="Enter your password"
                      value={password}
                      onChange={(e) => setPassword(e.target.value)}
                      style={{
                        width: '100%',
                        padding: '12px 12px 12px 40px',
                        background: 'rgba(255,255,255,0.1)',
                        border: '1px solid rgba(168, 85, 247, 0.3)',
                        borderRadius: '12px',
                        color: 'white',
                        fontSize: '16px',
                        outline: 'none',
                        transition: 'all 0.3s'
                      }}
                      required
                      disabled={loading}
                      onFocus={(e) => e.target.style.borderColor = '#a855f7'}
                      onBlur={(e) => e.target.style.borderColor = 'rgba(168, 85, 247, 0.3)'}
                    />
                  </div>
                </div>

                {/* Forgot Password Link */}
                <div style={{ textAlign: 'right' }}>
                  <a href="#" style={{ color: '#c084fc', fontSize: '14px', textDecoration: 'none' }}>
                    Forgot password?
                  </a>
                </div>

                {/* Login Button */}
                <button
                  type="submit"
                  disabled={loading}
                  style={{
                    position: 'relative',
                    width: '100%',
                    background: 'linear-gradient(135deg, #9333ea, #4f46e5)',
                    border: 'none',
                    borderRadius: '12px',
                    padding: '12px',
                    cursor: loading ? 'not-allowed' : 'pointer',
                    transition: 'all 0.3s'
                  }}
                >
                  <div style={{
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    gap: '8px',
                    background: 'rgba(15, 23, 42, 0.8)',
                    borderRadius: '12px',
                    padding: '12px',
                    transition: 'all 0.3s'
                  }}>
                    <span style={{ color: 'white', fontWeight: '500' }}>
                      {loading ? 'Authenticating...' : 'Login to Dashboard'}
                    </span>
                    {!loading && <FaArrowRight color="white" size={14} />}
                    {loading && (
                      <div style={{
                        width: '16px',
                        height: '16px',
                        border: '2px solid white',
                        borderTopColor: 'transparent',
                        borderRadius: '50%',
                        animation: 'spin 0.6s linear infinite'
                      }}></div>
                    )}
                  </div>
                </button>

                {/* Demo Credentials Hint */}
                <div style={{
                  marginTop: '16px',
                  padding: '12px',
                  background: 'rgba(168, 85, 247, 0.1)',
                  borderRadius: '8px',
                  border: '1px solid rgba(168, 85, 247, 0.2)'
                }}>
                  <p style={{ fontSize: '12px', color: '#d8b4fe', textAlign: 'center', margin: 0 }}>
                    🔐 Demo Credentials: <span style={{ fontFamily: 'monospace' }}>varshini</span> / <span style={{ fontFamily: 'monospace' }}>varshu</span>
                  </p>
                </div>
              </form>

              {/* Footer */}
              <div style={{
                marginTop: '24px',
                paddingTop: '16px',
                borderTop: '1px solid rgba(255,255,255,0.1)',
                textAlign: 'center'
              }}>
                <p style={{ fontSize: '12px', color: 'rgba(216, 180, 254, 0.7)', margin: 0 }}>
                  Secure admin access only • Protected by AI encryption
                </p>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Add animation keyframes */}
      <style>{`
        @keyframes blob {
          0%, 100% { transform: translate(0px, 0px) scale(1); }
          33% { transform: translate(30px, -50px) scale(1.1); }
          66% { transform: translate(-20px, 20px) scale(0.9); }
        }

        @keyframes spin {
          0% { transform: rotate(0deg); }
          100% { transform: rotate(360deg); }
        }

        @media (max-width: 768px) {
          .responsive-grid {
            grid-template-columns: 1fr !important;
          }
          .brand-section {
            display: none !important;
          }
          .mobile-brand {
            display: block !important;
          }
        }
      `}</style>
    </div>
  );
};

export default LoginPage;
